import React from "react";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  LineElement,
  CategoryScale,
  LinearScale,
  PointElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

// ✅ Register required Chart.js components
ChartJS.register(
  LineElement,
  CategoryScale,
  LinearScale,
  PointElement,
  Title,
  Tooltip,
  Legend
);

const Dashboard = () => {
  const chartOptions = {
    responsive: true,
    plugins: {
      legend: {
        display: true,
      },
    },
  };

  const chartData = {
    labels: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    datasets: [
      {
        label: "Sales",
        data: [30, 40, 35, 50, 49, 60, 70],
        borderColor: "rgba(75, 192, 192, 1)",
        backgroundColor: "rgba(75, 192, 192, 0.2)",
        borderWidth: 2,
        pointRadius: 5,
        pointBackgroundColor: "rgba(75, 192, 192, 1)",
      },
    ],
  };

  return (
    <div>
      <h1>Dashboard</h1>
      <div className="kpis">
        <div className="kpi">
          <h1>$100,000</h1>
          <p>Total Sales</p>
        </div>
        <div className="kpi">
          <h1>250</h1>
          <p>Total Inspections</p>
        </div>
        <div className="kpi">
          <h1>150</h1>
          <p>Active Users</p>
        </div>
        <div className="kpi">
          <h1>150</h1>
          <p>Active Users</p>
        </div>
      </div>
      {/* Render Line Chart */}
      <div className="charts">
        <Line className="chart-card" data={chartData} options={chartOptions} />
      </div>
    </div>
  );
};

export default Dashboard;
